terms1 = [
    {"tr": "İflas", "en": "Bankruptcy", "slug": "bankruptcy", "tag": "company-law", "def": "Bankruptcy is a legal proceeding involving a person or business that is unable to repay outstanding debts. Under Turkish Execution and Bankruptcy Law, it results in the liquidation of all attachable assets of the debtor to satisfy creditors.", "faq_q": "Who can be subject to bankruptcy in Turkey?", "faq_a": "Generally, merchants and those who are legally deemed merchants can be subject to bankruptcy proceedings."},
    {"tr": "Konkordato", "en": "Concordat", "slug": "concordat", "tag": "company-law", "def": "Concordat is a restructuring mechanism under Turkish Law allowing debtors in poor financial health to restructure their debts and avoid bankruptcy by reaching an agreement with their creditors, subject to court approval.", "faq_q": "What is the main advantage of concordat?", "faq_a": "It protects the debtor from execution proceedings and allows the business to continue operating while restructuring its debts."},
    {"tr": "İkale", "en": "Mutual Rescission", "slug": "mutual-rescission", "tag": "employment", "def": "Mutual rescission (İkale) is an agreement between an employer and an employee to terminate the employment contract by mutual consent, rather than through unilateral termination.", "faq_q": "Does ikale grant severance pay?", "faq_a": "By default, no, unless the parties explicitly agree to include severance-like compensation in the mutual rescission agreement."},
    {"tr": "İbra", "en": "Release Agreement", "slug": "release-agreement", "tag": "contract-law", "def": "A release agreement (İbra) is a contract where the creditor releases the debtor from their obligation, extinguishing the debt completely under the Turkish Code of Obligations.", "faq_q": "Can an employee release the employer before termination?", "faq_a": "Under Turkish Labor Law, release agreements signed before or immediately at termination are generally deemed invalid. They must be signed at least one month after termination."},
    {"tr": "Müteselsil Sorumluluk", "en": "Joint and Several Liability", "slug": "joint-and-several-liability", "tag": "contract-law", "def": "Joint and several liability means multiple parties are independently liable for the full amount of an obligation. The creditor may demand the entire performance from any one of the debtors.", "faq_q": "What happens if one debtor pays the full amount?", "faq_a": "The debtor who paid the full amount has a right of recourse against the other joint debtors for their respective shares."},
    {"tr": "Rücu", "en": "Right of Recourse", "slug": "right-of-recourse", "tag": "contract-law", "def": "The right of recourse allows a party who has discharged an obligation on behalf of another to seek reimbursement from the party who was primarily liable.", "faq_q": "When does the right of recourse typically arise?", "faq_a": "It often arises in insurance claims, joint liability cases, and suretyship, where one party pays a debt that rightfully belongs to another."},
    {"tr": "Sebepsiz Zenginleşme", "en": "Unjust Enrichment", "slug": "unjust-enrichment", "tag": "contract-law", "def": "Unjust enrichment occurs when a person retains money or benefits that in justice and equity belong to another, without a valid legal ground. The enriched party must return the benefit.", "faq_q": "What is the statute of limitations for unjust enrichment?", "faq_a": "Claims must be brought within two years of learning about the enrichment and the person enriched, and in any case within ten years from the enrichment itself."},
    {"tr": "Temerrüt", "en": "Default", "slug": "default", "tag": "contract-law", "def": "Default occurs when a debtor fails to fulfill a legal obligation, such as paying a debt when it becomes due, often requiring a formal notice of default to be legally established.", "faq_q": "What are the consequences of default?", "faq_a": "The debtor becomes liable for default interest, damages for delay, and the creditor may have the right to terminate the contract."},
    {"tr": "Muacceliyet", "en": "Acceleration / Exigibility", "slug": "exigibility", "tag": "contract-law", "def": "Exigibility (Muacceliyet) refers to the state where a debt becomes due and payable, meaning the creditor has the legal right to demand its immediate performance.", "faq_q": "What is an acceleration clause?", "faq_a": "An acceleration clause makes the entire balance of a debt due immediately if the debtor breaches certain conditions, such as missing an installment."},
    {"tr": "Muvazaa", "en": "Collusion / Simulation", "slug": "collusion-simulation", "tag": "contract-law", "def": "Simulation (Muvazaa) occurs when parties agree to create a false appearance of a legal transaction to deceive third parties, while secretly agreeing it will have no legal effect between them.", "faq_q": "Is a simulated contract valid?", "faq_a": "No, a simulated (fictitious) contract is absolutely null and void under Turkish Law, though the hidden true agreement may be valid if it meets form requirements."},
    {"tr": "İhtiyati Haciz", "en": "Preliminary Attachment", "slug": "preliminary-attachment", "tag": "dispute-resolution", "def": "Preliminary attachment is a provisional legal measure to seize a debtor's assets before or during a lawsuit to secure the collection of an unsecured monetary claim.", "faq_q": "Do you need a court order for preliminary attachment?", "faq_a": "Yes, a court order is required, and the creditor must usually deposit collateral to cover potential damages to the debtor if the claim proves unjustified."},
    {"tr": "İhtiyati Tedbir", "en": "Preliminary Injunction", "slug": "preliminary-injunction", "tag": "dispute-resolution", "def": "Preliminary injunction is a court order prohibiting or compelling a specific action to prevent irreparable harm or preserve the status quo pending final resolution of a dispute.", "faq_q": "What is the difference between attachment and injunction?", "faq_a": "Attachment secures monetary claims by seizing assets, while an injunction prevents changes to a disputed right or property (e.g., preventing the sale of a disputed house)."},
    {"tr": "Tacir", "en": "Merchant", "slug": "merchant", "tag": "commercial-law", "def": "A merchant under the Turkish Commercial Code is a real or legal person who operates a commercial enterprise. Merchants are subject to stricter standards of care and specific commercial rules.", "faq_q": "Are all companies considered merchants?", "faq_a": "Yes, commercial companies (like Joint-Stock and Limited companies) are legally deemed merchants from the moment of their incorporation."},
    {"tr": "Ticari İşletme Devri", "en": "Transfer of Commercial Enterprise", "slug": "transfer-of-commercial-enterprise", "tag": "commercial-law", "def": "This involves transferring a business as a going concern, including its assets, liabilities, and goodwill. It requires a written agreement registered with the Trade Registry.", "faq_q": "Does the transferor remain liable for past debts?", "faq_a": "Yes, under Turkish Law, the transferor remains jointly and severally liable with the transferee for the enterprise's pre-existing debts for two years."},
    {"tr": "Esas Sözleşme", "en": "Articles of Association", "slug": "articles-of-association", "tag": "company-law", "def": "Articles of Association is the foundational constitutional document of a company, defining its name, purpose, headquarters, capital structure, and internal governance rules.", "faq_q": "Can the Articles of Association be amended?", "faq_a": "Yes, amendments require a resolution by the General Assembly meeting specific quorum and majority requirements, followed by Trade Registry registration."},
    {"tr": "Tür Değiştirme", "en": "Change of Company Type", "slug": "change-of-company-type", "tag": "company-law", "def": "A legal process where a company changes its corporate form (e.g., from a Limited Company to a Joint-Stock Company) without undergoing liquidation, preserving its legal continuity.", "faq_q": "Does changing the company type affect existing contracts?", "faq_a": "No, because the company's legal personality continues, all its rights, assets, and liabilities remain intact and contracts continue seamlessly."},
    {"tr": "Bölünme", "en": "Spin-off / Demerger", "slug": "spin-off", "tag": "company-law", "def": "Demerger is a corporate restructuring process where a company divides its assets and liabilities into two or more existing or newly formed companies.", "faq_q": "What is the difference between full and partial demerger?", "faq_a": "In a full demerger, the original company is dissolved. In a partial demerger, the original company survives but transfers a portion of its business to another entity."},
    {"tr": "Tasfiye", "en": "Liquidation", "slug": "liquidation", "tag": "company-law", "def": "Liquidation is the process of winding up a company's affairs, selling its assets, settling its debts, and distributing any remaining balance to shareholders before dissolving the legal entity.", "faq_q": "How long does liquidation take in Turkey?", "faq_a": "The minimum legal period for liquidation is generally three months from the final announcement to creditors, but in practice, it often takes longer."},
    {"tr": "Ticaret Sicili", "en": "Trade Registry", "slug": "trade-registry", "tag": "commercial-law", "def": "The Trade Registry is an official public record system in Turkey where merchants and companies must register their fundamental corporate information, ensuring transparency and legal certainty.", "faq_q": "Are Trade Registry records public?", "faq_a": "Yes, anyone can access and request copies of registered documents, and key registrations are published in the Trade Registry Gazette."},
    {"tr": "İmza Sirküleri", "en": "Signature Circular", "slug": "signature-circular", "tag": "company-law", "def": "A signature circular is a notarized document displaying the specimen signatures of a company's authorized representatives, proving their authority to bind the company.", "faq_q": "Is a signature circular always required?", "faq_a": "Yes, in Turkey, banks, government offices, and commercial partners strictly require a valid signature circular to verify a representative's signing authority."},
    {"tr": "Tescil", "en": "Registration", "slug": "registration", "tag": "commercial-law", "def": "Registration refers to the formal recording of specific legal facts or corporate actions (like company formation or board elections) into official registries, such as the Trade Registry.", "faq_q": "What is the legal effect of registration?", "faq_a": "Depending on the matter, registration can be constitutive (creating the right, like forming a company) or declarative (making an existing fact enforceable against third parties)."},
    {"tr": "İlan", "en": "Announcement / Publication", "slug": "announcement", "tag": "commercial-law", "def": "Publication refers to the legal requirement to announce specific corporate actions in the Turkish Trade Registry Gazette to inform third parties and creditors.", "faq_q": "What actions must be announced?", "faq_a": "Company incorporation, capital changes, mergers, liquidations, and appointments of authorized signatories must be officially published."},
    {"tr": "Ortaklar Kurulu", "en": "Board of Partners", "slug": "board-of-partners", "tag": "company-law", "def": "The Board of Partners is the supreme decision-making body in a Limited Liability Company (Limited Şirket), equivalent to the General Assembly in a Joint-Stock Company.", "faq_q": "What decisions does the Board of Partners make?", "faq_a": "They approve financials, amend the articles of association, appoint managers, and decide on capital increases and profit distribution."},
    {"tr": "Peçeleme", "en": "Circumvention of Law", "slug": "circumvention-of-law", "tag": "contract-law", "def": "Circumvention of law (Peçeleme) occurs when parties use a legally valid transaction to bypass a mandatory legal prohibition, effectively achieving a forbidden outcome.", "faq_q": "Is circumvention of law illegal?", "faq_a": "Yes, Turkish courts apply the mandatory rules that the parties attempted to bypass, often rendering the circumventing transaction invalid."},
    {"tr": "Tüzel Kişilik Perdesinin Aralanması", "en": "Piercing the Corporate Veil", "slug": "piercing-the-corporate-veil", "tag": "company-law", "def": "An exceptional legal doctrine allowing courts to ignore limited corporate liability and hold shareholders personally liable if the corporate form is abused to defraud creditors.", "faq_q": "When do courts pierce the corporate veil?", "faq_a": "Courts apply it strictly, usually only when there is severe commingling of personal and corporate assets or blatant fraud bypassing legal obligations."},
    {"tr": "Sermaye Taahhüdü", "en": "Capital Commitment", "slug": "capital-commitment", "tag": "company-law", "def": "Capital commitment is the legally binding promise made by shareholders to contribute a specific amount of capital to a company during incorporation or a capital increase.", "faq_q": "When must capital commitments be paid?", "faq_a": "At least 25% of cash capital must be paid before registration of a Joint-Stock Company; the remaining 75% must be paid within 24 months."},
    {"tr": "Rüçhan Hakkı", "en": "Pre-emption Right", "slug": "pre-emption-right", "tag": "company-law", "def": "Pre-emption right allows existing shareholders to maintain their proportional ownership by having the first right to purchase newly issued shares during a capital increase.", "faq_q": "Can pre-emption rights be restricted?", "faq_a": "Yes, the General Assembly can restrict or revoke pre-emption rights for justifiable reasons (e.g., acquiring another company), provided specific majority requirements are met."},
    {"tr": "Nama Yazılı Pay", "en": "Registered Shares", "slug": "registered-shares", "tag": "company-law", "def": "Registered shares are corporate shares issued in the name of a specific person and recorded in the company's share ledger. Their transfer requires endorsement and ledger registration.", "faq_q": "Can transfer of registered shares be restricted?", "faq_a": "Yes, a company's articles of association can stipulate that registered shares can only be transferred with the board of directors' approval."},
    {"tr": "Hamiline Yazılı Pay", "en": "Bearer Shares", "slug": "bearer-shares", "tag": "company-law", "def": "Bearer shares do not contain the owner's name; whoever physically holds the share certificate is deemed the owner. Their transfer simply requires handing over possession.", "faq_q": "Are there new tracking rules for bearer shares?", "faq_a": "Yes, to prevent money laundering, Turkey now requires bearer shareholders to be registered with the Central Securities Depository (MKK)."},
    {"tr": "İntifa Senedi", "en": "Dividend Right Certificate", "slug": "dividend-right-certificate", "tag": "company-law", "def": "These are certificates that do not represent share capital or grant voting rights, but provide the holder with financial rights, such as a share of the company's net profit.", "faq_q": "Who typically receives dividend right certificates?", "faq_a": "They are often granted to founders, specific creditors, or individuals who contributed significant know-how or services to the company."},
    {"tr": "Çıkarma Hakkı", "en": "Squeeze-out Right", "slug": "squeeze-out-right", "tag": "company-law", "def": "A mechanism in M&A law allowing a controlling shareholder (usually holding over 98%) to force minority shareholders to sell their shares at a fair price, taking the company private.", "faq_q": "Why is the squeeze-out right used?", "faq_a": "It simplifies corporate governance and reduces compliance costs by removing small minority stakes after a major acquisition."},
    {"tr": "Satma Hakkı", "en": "Sell-out Right", "slug": "sell-out-right", "tag": "company-law", "def": "The counterpart to the squeeze-out, this gives minority shareholders the right to demand that the controlling shareholder purchase their shares at a fair price.", "faq_q": "When can minority shareholders use this right?", "faq_a": "Typically, when a controlling shareholder acquires a dominant stake (e.g., 98%), minority shareholders can force the controller to buy them out."},
    {"tr": "Birlikte Satma Hakkı", "en": "Tag-Along Right", "slug": "tag-along-right", "tag": "company-law", "def": "A contractual right protecting minority shareholders. If the majority shareholder sells their stake, minority shareholders can join the transaction and sell their shares under the same terms.", "faq_q": "Where are tag-along rights defined?", "faq_a": "They are not statutory under Turkish Commercial Code but are heavily utilized and strictly defined in Shareholders Agreements (SHA)."},
    {"tr": "Birlikte Satışa Zorlama Hakkı", "en": "Drag-Along Right", "slug": "drag-along-right", "tag": "company-law", "def": "A contractual right allowing a majority shareholder to force minority shareholders to join in the sale of the company to a third party on the same terms.", "faq_q": "What is the benefit of a drag-along right?", "faq_a": "It prevents minority shareholders from blocking the sale of 100% of the company, making the company more attractive to potential buyers."},
    {"tr": "Ön Alım Hakkı", "en": "Right of First Refusal", "slug": "right-of-first-refusal", "tag": "company-law", "def": "A contractual right requiring a shareholder who wishes to sell their shares to a third party to first offer those shares to existing shareholders on the exact same terms.", "faq_q": "Is right of first refusal recognized for real estate?", "faq_a": "Yes, legal right of first refusal automatically exists between co-owners of real estate under Turkish Civil Law."},
    {"tr": "İlk Teklif Hakkı", "en": "Right of First Offer", "slug": "right-of-first-offer", "tag": "company-law", "def": "A contractual obligation where a shareholder looking to sell must first ask existing shareholders to make an offer for the shares before negotiating with outside parties.", "faq_q": "How does it differ from Right of First Refusal?", "faq_a": "Right of first offer requires the seller to ask partners for an offer *before* seeking third-party deals, whereas right of first refusal gives partners the right to match an *already secured* third-party deal."},
    {"tr": "Opsiyon", "en": "Option", "slug": "option", "tag": "contract-law", "def": "A financial derivative or contractual right (but not obligation) to buy or sell an asset at a predetermined price within a specific timeframe.", "faq_q": "Are options commonly used in Turkish M&A?", "faq_a": "Yes, call and put options are heavily used in Shareholders Agreements to plan future exits or resolve deadlocks."},
    {"tr": "Alım Opsiyonu", "en": "Call Option", "slug": "call-option", "tag": "contract-law", "def": "A contractual right granting the holder the option to purchase shares or assets at an agreed-upon price within a specific period.", "faq_q": "How are call options used in joint ventures?", "faq_a": "A majority partner may use a call option to buy out the minority partner based on performance metrics or after a certain number of years."},
    {"tr": "Satım Opsiyonu", "en": "Put Option", "slug": "put-option", "tag": "contract-law", "def": "A contractual right granting the holder the option to force another party to buy their shares or assets at a predetermined price.", "faq_q": "Why would an investor demand a put option?", "faq_a": "It guarantees an exit strategy, ensuring the investor can sell their stake back to the founders at a guaranteed return if an IPO doesn't occur."},
    {"tr": "Kredi Sözleşmesi", "en": "Loan Agreement", "slug": "loan-agreement", "tag": "contract-law", "def": "A formal contract between a lender and borrower detailing the principal loan amount, interest rates, repayment schedule, and covenants.", "faq_q": "What governs commercial loans in Turkey?", "faq_a": "Commercial loan agreements are primarily governed by the Turkish Code of Obligations and banking regulations."},
    {"tr": "Sendikasyon Kredisi", "en": "Syndicated Loan", "slug": "syndicated-loan", "tag": "commercial-law", "def": "A large loan provided by a group of lenders (a syndicate) to a single borrower, distributing the credit risk among the participating banks.", "faq_q": "Who uses syndicated loans?", "faq_a": "They are typically used by large corporations or states for major infrastructure projects, M&A financing, or large-scale capital needs."},
    {"tr": "Proje Finansmanı", "en": "Project Finance", "slug": "project-finance", "tag": "commercial-law", "def": "The long-term financing of infrastructure or industrial projects based upon the projected cash flows of the project rather than the balance sheets of its sponsors.", "faq_q": "What secures project finance?", "faq_a": "The loan is secured primarily by the project's assets, rights, and future revenue streams, creating a non-recourse or limited-recourse structure."},
    {"tr": "Temlik", "en": "Assignment", "slug": "assignment", "tag": "contract-law", "def": "The legal transfer of a right, property, or claim from one party (assignor) to another (assignee), frequently used for transferring receivables.", "faq_q": "Does assignment require the debtor's consent?", "faq_a": "No, assignment of receivables generally does not require the debtor's consent, but the debtor must be notified to make payment to the new creditor."},
    {"tr": "Alacağın Devri", "en": "Assignment of Receivables", "slug": "assignment-of-receivables", "tag": "contract-law", "def": "A specific form of assignment where a creditor transfers their right to collect a debt to a third party. It must be executed in writing under Turkish Law.", "faq_q": "Can future receivables be assigned?", "faq_a": "Yes, future receivables can be assigned as long as they are determinable at the time of the assignment."},
    {"tr": "Borcun Üstlenilmesi", "en": "Assumption of Debt", "slug": "assumption-of-debt", "tag": "contract-law", "def": "A legal process where a third party takes over a debtor's obligation, relieving the original debtor of their liability.", "faq_q": "Does assumption of debt require the creditor's consent?", "faq_a": "Yes, unlike the assignment of receivables, transferring a debt to a new debtor absolutely requires the explicit consent of the creditor."},
    {"tr": "Kefalet", "en": "Surety", "slug": "surety", "tag": "contract-law", "def": "A personal guarantee where a third party (the surety) undertakes to pay the creditor if the primary debtor fails to fulfill their obligation.", "faq_q": "What are the formal requirements for a surety agreement?", "faq_a": "It must be in writing, and the maximum guaranteed amount and the date of the surety must be handwritten by the surety personally. Spousal consent is also generally required."},
    {"tr": "Aval", "en": "Aval", "slug": "aval", "tag": "commercial-law", "def": "Aval is a specialized form of guarantee used exclusively for negotiable instruments (like bills of exchange), where a third party guarantees payment on behalf of one of the signatories.", "faq_q": "How is an aval given?", "faq_a": "It is typically given by writing 'for aval' (aval içindir) and signing on the front of the negotiable instrument."},
    {"tr": "Ciro", "en": "Endorsement", "slug": "endorsement", "tag": "commercial-law", "def": "The act of signing the back of a negotiable instrument (like a cheque or promissory note) to transfer the rights inherent in the instrument to another party.", "faq_q": "What is a blank endorsement?", "faq_a": "A blank endorsement consists of only the signature of the endorser, effectively turning the instrument into a bearer instrument."},
    {"tr": "Poliçe", "en": "Bill of Exchange", "slug": "bill-of-exchange", "tag": "commercial-law", "def": "A written, unconditional order by one party (drawer) directing another party (drawee) to pay a specific sum of money to a third party (payee) at a set future date.", "faq_q": "Are bills of exchange common in Turkey?", "faq_a": "While legally regulated, cheques and promissory notes are vastly more common in Turkish commercial practice than traditional bills of exchange."},
    {"tr": "Çek", "en": "Cheque", "slug": "cheque", "tag": "commercial-law", "def": "A commercial negotiable instrument ordering a bank to pay a specific amount of money from a person's account to the bearer or named payee.", "faq_q": "What happens if a cheque bounces in Turkey?", "faq_a": "Issuing a bounced cheque is a serious matter in Turkey and can lead to severe civil penalties, banking bans, and criminal prosecution."}
]
